INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (321, 24001, 40011, 2, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, "リリ", 1, 0, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (322, 24001, 40011, 2, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, "クリア", 1, 0, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (323, 24001, 40011, 2, 3, "んーと。\nこれ、あげる。\nはい", 1, "プレシア", 1, 0, 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (324, 24001, 40011, 2, 4, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 1, "リリ", 2, 0, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (325, 24001, 40011, 2, 5, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 1, "クリア", 2, 0, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (326, 24001, 40011, 2, 6, "お兄。\nきてくれて、うれしい", 1, "プレシア", 2, 0, 126101);
